messages.content:
你是 marketting-planning-intent 项目的 attribute agent。
只归因当前单轮 intent-recognition 链路：request_normalization、intent_api_call、adapter_extraction、label_mapping；不要把 planning/SSE generation 的问题归入本项目。
优先使用 intent_contract_probe 定位 intent label、required slots/entities、confidence threshold、fallback policy 或 label_mapping 的当前证据差异。
只能输出 AttributeResult JSON 所需字段；证据不足时用 evidence_strength=none/weak 和 root_cause_hypothesis 表达缺口。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "意图标签准确识别为客户画像意图",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "reason": "API返回意图为'其他意图'而非customer_portrait，编码4001"
        },
        {
          "stage": "adapter_extraction",
          "reason": "适配器未纠正错误意图，直接输出other"
        }
      ],
      "root_cause_hypothesis": "意图识别API的底层模型或提示未能将查询分类为客户画像意图，导致返回'其他意图'(4001)；适配器未进行二次验证或回退，直接采纳该错误意图。",
      "evidence": [
        {
          "source": "intent_api_call raw_response",
          "content": "intent: 4001, intent_name: 其他意图"
        },
        {
          "source": "adapter_extraction",
          "content": "intent: other, confidence: 0.5"
        },
        {
          "source": "intent_contract_probe",
          "content": "expected: customer_portrait, actual: other"
        }
      ]
    },
    {
      "expectation_id": "提取关键业务实体-产品名“重疾险”",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "reason": "API响应未包含产品实体信息"
        },
        {
          "stage": "adapter_extraction",
          "reason": "未从响应中提取或生成target_value"
        }
      ],
      "root_cause_hypothesis": "意图识别API未进行槽位提取或返回空实体列表；适配器未能识别缺失的产品信息，也未通过其他方式获取。",
      "evidence": [
        {
          "source": "adapter_extraction",
          "content": "target_value: null"
        },
        {
          "source": "intent_api_call raw_response",
          "content": "响应中未见target_value或product字段"
        }
      ]
    },
    {
      "expectation_id": "置信度达到可接受阈值",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "reason": "API返回置信度0.5，低于预期0.9"
        }
      ],
      "root_cause_hypothesis": "模型对查询分类信心不足，可能因训练数据或提示限制，未能给出高置信度的正确分类。",
      "evidence": [
        {
          "source": "adapter_extraction",
          "content": "confidence: 0.5"
        },
        {
          "source": "reference_contract",
          "content": "expected confidence >= 0.9"
        }
      ]
    },
    {
      "expectation_id": "不应归为兜底意图“other”",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "reason": "模型将查询分类为other/4001"
        },
        {
          "stage": "label_mapping",
          "reason": "映射表将4001映射为other，符合配置但导致兜底"
        }
      ],
      "root_cause_hypothesis": "与意图标签错误同源，API输出other意图导致落入兜底逻辑。",
      "evidence": [
        {
          "source": "adapter_extraction",
          "content": "intent: other"
        },
        {
          "source": "label_mapping evidence",
          "content": "intent: other"
        }
      ]
    },
    {
      "expectation_id": "调度边界正确指向客户画像功能",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        {
          "stage": "intent_api_call",
          "reason": "意图错误导致下游调度无法路由到客户画像服务"
        }
      ],
      "root_cause_hypothesis": "下游调度依赖意图识别结果，由于意图为other，无法启动客户画像模块，属于上游错误的连锁影响。",
      "evidence": [
        {
          "source": "adapter_extraction",
          "content": "intent: other"
        }
      ]
    }
  ],
  "suspected_locations": [
    {
      "stage": "intent_api_call",
      "file": "app/workflow/steps/intent_recognition.py",
      "detail": "API请求或响应处理逻辑可能存在缺陷，未对低置信度或错误意图进行修正"
    },
    {
      "stage": "adapter_extraction",
      "file": "app/workflow/steps/intent_recognition.py",
      "detail": "提取和映射逻辑未能纠正错误意图或补充缺失槽位"
    },
    {
      "stage": "label_mapping",
      "file": "projects/marketting-planning-intent/intent.py",
      "detail": "映射表正确但上游错误无法挽回"
    }
  ],
  "root_cause_hypothesis": "根本原因在于意图识别API（intent_api_call阶段）将用户查询误分类为“其他意图”（编码4001），未提取产品实体，且输出置信度低（0.5）。该错误可能源于LLM提示设计不足或模型训练数据未覆盖客户画像场景。adapter_extraction阶段未对API输出进行置信度阈值校验或意图纠错，直接传递了错误结果。label_mapping阶段虽正确映射，但无法补偿上游错误，最终导致所有下游期望失败。",
  "evidence": [
    {
      "type": "api_raw_response",
      "content": "{\"code\":0,\"msg\":\"success\",\"data\":{\"robot_text\":\"其他意图\",\"extra_output_params\":{\"intent\":\"4001\",\"intent_name\":\"其他意图\"}}}"
    },
    {
      "type": "adapter_output",
      "content": "{\"intent\":\"other\",\"confidence\":0.5,\"target_value\":null}"
    },
    {
      "type": "runtime_check",
      "content": "raw_intent=None, actual_mapping=other, expected_intent=customer_portrait"
    },
    {
      "type": "intent_contract_probe",
      "content": "intent_match: false, actual_intent: other, confidence: 0.5"
    }
  ],
  "evidence_strength": "strong"
}

